// AG2.01 — Normalize Input (robuste, conserve intraday+daily)

const input = $input.first()?.json ?? {};

function nowIso() { return new Date().toISOString(); }

function toInt(v, dflt) {
  const n = Number(v);
  return Number.isFinite(n) ? n : dflt;
}

function cleanSym(s) {
  return String(s ?? "").trim();
}

// Symbols
let symbols = Array.isArray(input.symbols) ? input.symbols : [];
symbols = symbols.map(cleanSym).filter(Boolean);

// Versions / ids
const run_id = input.run_id ?? input.runId ?? "";
const strategy_version = input.strategy_version ?? input.strategyVersion ?? "STRAT_1.0.0";
const config_version = input.config_version ?? input.configVersion ?? "CFG_1.0.0";

// Infra
const timezone = input.timezone ?? input.timezone_name ?? input.timezoneName ?? "Europe/Paris";
// APRÈS (Port 8000)
const yfinance_api_base = input.yfinance_api_base ?? input.yfinanceApiBase ?? "http://yfinance-api:8000";

// Base (compat ancien format)
const baseInterval = String(input.interval ?? "1h");
const baseLookback = toInt(input.lookback_days ?? input.lookbackDays ?? 60, 60);
const baseMaxBars = toInt(input.max_bars ?? input.maxBars ?? 200, 200);

// Timeframes (nouveau format)
const intradayIn = (input.intraday && typeof input.intraday === "object") ? input.intraday : {};
const dailyIn = (input.daily && typeof input.daily === "object") ? input.daily : {};

const intraday = {
  interval: String(intradayIn.interval ?? baseInterval ?? "1h"),
  lookback_days: toInt(intradayIn.lookback_days ?? intradayIn.lookbackDays ?? baseLookback, 60),
  max_bars: toInt(intradayIn.max_bars ?? intradayIn.maxBars ?? baseMaxBars, 200),
  role: String(intradayIn.role ?? "timing"),
};

const daily = {
  interval: String(dailyIn.interval ?? "1d"),
  lookback_days: toInt(dailyIn.lookback_days ?? dailyIn.lookbackDays ?? 400, 400),
  max_bars: toInt(dailyIn.max_bars ?? dailyIn.maxBars ?? 400, 400),
  role: String(dailyIn.role ?? "strategy"),
};

const out = {
  run_id,
  strategy_version,
  config_version,
  timezone,
  yfinance_api_base,

  // compat: on garde aussi le "base" (intraday) au top-level
  interval: intraday.interval,
  lookback_days: intraday.lookback_days,
  max_bars: intraday.max_bars,

  intraday,
  daily,

  symbols,
  symbols_count: symbols.length,
  generatedAt: nowIso(),
};

if (!symbols.length) {
  return [{
    json: {
      run_id: out.run_id || `RUN_${nowIso().replace(/[-:.TZ]/g,"")}`,
      ok: false,
      error: "NO_SYMBOLS",
      message: "Input.symbols is empty. Provide at least 1 symbol (ex: TTE.PA).",
      received: input,
      generatedAt: nowIso(),
    }
  }];
}

return [{ json: { ok: true, ...out } }];

// AG2.02 — Explode Symbols (Run Once for All Items)
// Produces 1 item per symbol, carrying shared config.

const cfg = $input.first().json;

if (!cfg.ok) {
  // pass-through error item (single)
  return [{ json: cfg }];
}

const out = [];
for (let i = 0; i < cfg.symbols.length; i++) {
  out.push({
    json: {
      ...cfg,
      symbol: cfg.symbols[i],
      _symbol_index: i,
      // remove large arrays from per-item payload
      symbols: undefined,
    }
  });
}
return out;

// AG2.98 — Error Pack (Run Once for All Items)
const it = $input.first()?.json ?? {};
return [{
  json: {
    run_id: it.run_id || null,
    agent_id: it.agent_id || "AGENT_2_TECHNICAL",
    generatedAt: new Date().toISOString(),
    interval: it.interval || null,
    universeCoverage: { processed: 0, ok: 0, failed: 0, symbols_ok: [], symbols_failed: [] },
    technicalSignals: [],
    failures: [it],
    ok: false,
    error: it.error || "UPSTREAM_ERROR",
    message: it.message || "Upstream returned ok=false; no symbols processed."
  }
}];

// AG2.99 — Aggregate Pack (v3.2) — Consolidate + Full Indicators Propagation (H1/D1) + Flatten for DB
const rawItems = $input.all().map(i => i.json ?? {});
const now = new Date().toISOString();

// 1) Merge by symbol
const bySym = {};
let globalRunId = "";

for (const it of rawItems) {
  if (it.run_id) globalRunId = it.run_id;
  const sym = (it.symbol ?? "").trim();
  if (!sym) continue;

  if (!bySym[sym]) bySym[sym] = { ...it };
  else bySym[sym] = { ...bySym[sym], ...it };

  // Keep technical blocks if present
  if (it.technical_analysis) bySym[sym].technical_analysis = it.technical_analysis;
  if (it.technical_analysis_1d) bySym[sym].technical_analysis_1d = it.technical_analysis_1d;
}

const consolidated = Object.values(bySym);

// 2) Indicator keys to propagate (your full set)
const IND_KEYS = [
  "sma20",
  "sma50",
  "sma200",
  "ema12",
  "ema26",
  "macd",
  "macd_signal",
  "macd_hist",
  "rsi14",
  "volatility_ann",
  "last_close",
  "atr_value",
  "atr_pct",
  "resistance_level_50",
  "dist_to_res_pct_50",
];

// Helpers
const pickVal = (obj, key) => {
  // returns null if missing/undefined; preserves 0
  const v = obj?.[key];
  return (v === undefined) ? null : v;
};

const firstNonNull = (...vals) => {
  for (const v of vals) {
    if (v !== null && v !== undefined) return v;
  }
  return null;
};

// 3) Build “signals” array
const signals = consolidated.map(x => {
  const h1 = x.technical_analysis?.signal ?? null;
  const d1 = x.technical_analysis_1d?.signal ?? null;

  // --- Recuperation Métadonnées H1 & D1 ---
  const h1_meta = {
    date: x.technical_analysis?.last_candle_date ?? null,
    source: x.technical_analysis?.data_source ?? "unknown",
    status: x.technical_analysis?.status ?? null,
    warnings: x.technical_analysis?.warnings ?? [],
  };
  const d1_meta = {
    date: x.technical_analysis_1d?.last_candle_date ?? null,
    source: x.technical_analysis_1d?.data_source ?? "unknown",
    status: x.technical_analysis_1d?.status ?? null,
    warnings: x.technical_analysis_1d?.warnings ?? [],
  };
  // ----------------------------------------

  // Pull indicator blocks
  const indH1Raw = x.technical_analysis?.indicators ?? {};
  const indD1Raw = x.technical_analysis_1d?.indicators ?? {};

  // Build propagated indicators (H1 / D1) + canonical with fallback (D1 -> H1 -> top-level)
  const indicators_h1 = {};
  const indicators_d1 = {};
  const indicators = {};
  const flat = {};

  for (const k of IND_KEYS) {
    const vD1 = pickVal(indD1Raw, k);
    const vH1 = pickVal(indH1Raw, k);

    // Some workflows may already expose indicators at top-level (defensive)
    const vTop = pickVal(x, k);

    indicators_d1[k] = vD1;
    indicators_h1[k] = vH1;

    // Canonical: D1 first, else H1, else top-level
    indicators[k] = firstNonNull(vD1, vH1, vTop);

    // Flatten for DB (optional but very useful)
    flat[k] = indicators[k];
    flat[`d1_${k}`] = vD1;
    flat[`h1_${k}`] = vH1;
  }

  // Price Fallback Logic (now uses canonical indicators)
  const trend = {
    last_close: indicators.last_close,
    sma200: indicators.sma200,
  };

  const aiRaw = x.ai_raw ?? null;

  return {
    symbol: x.symbol ?? null,

    // H1 / D1 + METADATA
    h1,
    d1,
    h1_meta,
    d1_meta,

    // Backward compatible
    trend,

    // NEW: full indicators propagation
    indicators,      // canonical (D1 -> H1 -> top-level)
    indicators_h1,   // raw H1
    indicators_d1,   // raw D1

    // Flattened fields for DB updates (k, h1_k, d1_k)
    ...flat,

    // Filter + routing
    pass_to_ai: x.pass_to_ai ?? false,
    pass_to_pm: x.pass_to_pm ?? false,
    reason: x.reason ?? null,

    // Signature / dedup
    sig_hash: x.sig_hash ?? null,
    sig_json: x.sig_json ?? null,
    call_ai: x.call_ai ?? false,
    dedup_reason: x.dedup_reason ?? null,
    ttl_minutes: x.ttl_minutes ?? null,
    cache_hit: x.cache_hit ?? false,

    // AI normalized fields
    ai_decision: x.ai_decision ?? (aiRaw?.decision ?? null),
    ai_validated: x.ai_validated ?? (aiRaw?.validated ?? null),
    ai_quality_score: x.ai_quality_score ?? (aiRaw?.quality_score ?? null),
    ai_reasoning: x.ai_reasoning ?? (aiRaw?.reasoning ?? null),
    ai_chart_pattern: x.ai_chart_pattern ?? (aiRaw?.chart_pattern ?? null),
    ai_stop_loss_suggestion: x.ai_stop_loss_suggestion ?? (aiRaw?.stop_loss_suggestion ?? null),
    ai_stop_loss_basis: x.ai_stop_loss_basis ?? (aiRaw?.stop_loss_basis ?? null),

    ai_bias_sma200: x.ai_bias_sma200 ?? (aiRaw?.bias_sma200 ?? null),
    ai_regime_d1: x.ai_regime_d1 ?? (aiRaw?.regime_d1 ?? null),
    ai_h1_d1_alignment: x.ai_h1_d1_alignment ?? (aiRaw?.h1_d1_alignment ?? null),

    // Keep json strings stable for DB
    ai_missing_fields_json: x.ai_missing_fields_json ?? JSON.stringify(aiRaw?.missing_fields ?? x.ai_missing_fields ?? []),
    ai_anomalies_json: x.ai_anomalies_json ?? JSON.stringify(aiRaw?.anomalies ?? []),

    // Raw AI (audit)
    ai_raw: aiRaw,
  };
});

const counts = {
  total_in_batch: rawItems.length,
  consolidated: consolidated.length,
  pass_to_ai: signals.filter(s => s.pass_to_ai).length,
  pass_to_pm: signals.filter(s => s.pass_to_pm).length,
  ai_called: signals.filter(s => s.call_ai).length,
  ai_returned: signals.filter(s => !!s.ai_raw || !!s.ai_reasoning).length,
};

return [{
  json: {
    ok: true,
    run_id: globalRunId,
    source: "AG2_TECHNICAL_ANALYST",
    counts,
    signals,
    generatedAt: now,
  }
}];

// AG2.39 — Pre-Filter Logic (Smart Filter H1+D1) - BLINDÉ
// - SELL passe toujours
// - BUY requiert tendance haussière OU signal fort OU historique insuffisant (bénéfice du doute)

const items = $input.all();

return items.map((it) => {
  const j = it.json ?? {};
  const h1 = j.technical_analysis;
  const d1 = j.technical_analysis_1d;

  // 1. Pas de signal H1 => Poubelle
  if (!h1 || !h1.signal || !h1.signal.action) {
    return { json: { ...j, pass_to_ai: false, reason: "NO_H1_SIGNAL" } };
  }

  // 2. SELL => Priorité Absolue (Sécurité Portefeuille)
  if (h1.signal.action === "SELL") {
    return { json: { ...j, pass_to_ai: true, reason: "SELL_SIGNAL_SAFETY" } };
  }

  // 3. NEUTRAL => Poubelle (Bruit)
  if (h1.signal.action === "NEUTRAL") {
    return { json: { ...j, pass_to_ai: false, reason: "NEUTRAL" } };
  }

  // 4. Analyse du Contexte Daily pour les BUY
  // Si pas de D1 du tout => Rejet (trop dangereux de trader à l'aveugle)
  if (!d1 || !d1.indicators) {
    return { json: { ...j, pass_to_ai: false, reason: "NO_DAILY_CONTEXT" } };
  }

  const price = d1.indicators.last_close;
  const sma200 = d1.indicators.sma200;

  // Est-ce qu'on est en tendance haussière ?
  // Si SMA200 existe : Prix > SMA200
  // Si SMA200 n'existe pas (IPO récente) : On considère que c'est neutre/haussier par défaut pour ne pas bloquer
  let isTrendBullish = false;
  if (typeof sma200 === "number" && typeof price === "number") {
      isTrendBullish = (price > sma200);
  } else if (sma200 === null) {
      // Cas IPO récente : on laisse sa chance au signal H1
      isTrendBullish = true; 
  }

  // RÈGLE 2 : BUY classique (avec la tendance)
  if (h1.signal.action === "BUY" && isTrendBullish) {
    return { json: { ...j, pass_to_ai: true, reason: "BUY_IN_UPTREND" } };
  }

  // RÈGLE 3 : BUY contre tendance (Rebond technique violent)
  // On exige un signal technique H1 impeccable (Score >= 3) OU un RSI en survente extrême (< 30)
  const rsi = h1.indicators?.rsi14;
  const score = h1.signal?.score;
  const isStrongSignal = (typeof score === "number" && score >= 3) || (typeof rsi === "number" && rsi < 30);

  if (h1.signal.action === "BUY" && !isTrendBullish && isStrongSignal) {
    return { json: { ...j, pass_to_ai: true, reason: "STRONG_REVERSAL_BUY" } };
  }

  // RÈGLE 4 : Tout le reste (Achat faible sous MM200) => Poubelle
  return { json: { ...j, pass_to_ai: false, reason: "WEAK_BUY_AGAINST_TREND" } };
});

// AG2.17B — Normalize Daily Output
// But: renommer technical_analysis -> technical_analysis_1d

const items = $input.all();

return items.map((it) => {
  const j = it.json ?? {};
  if (j.technical_analysis && !j.technical_analysis_1d) {
    j.technical_analysis_1d = j.technical_analysis;
    delete j.technical_analysis;
  }
  return { json: j };
});

// AG2.41B — Extract AI Result (Normalized) + output_ref
// Entrée typique OpenAI(n8n): { output: [ { content: [ { text: {...} | "{...json...}" } ] } ] }
// Objectif :
// 1) extraire tous les champs du validator
// 2) normaliser les cas limites (bars manquantes => WATCH si WITH_BIAS, etc.)
// 3) produire un output_ref stable pour cache / stockage

const root = $json ?? {};
const msg = root.output?.[0] ?? null;
const c0 = msg?.content?.[0] ?? null;

let payload = c0?.text ?? null;

// Certains setups renvoient une string JSON
if (typeof payload === "string") {
  try { payload = JSON.parse(payload); } catch (e) { /* ignore */ }
}

// Helpers
function isNil(v) { return v === null || v === undefined; }
function toNumberOrNull(v) {
  if (typeof v === "number") return v;
  if (typeof v === "string" && v.trim() !== "") {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  }
  return null;
}
function toIntOrNull(v) {
  const n = toNumberOrNull(v);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}
function toStringOrNull(v) {
  if (typeof v === "string") return v;
  if (isNil(v)) return null;
  return String(v);
}
function toArrayOrEmpty(v) {
  return Array.isArray(v) ? v : [];
}
function clampInt(n, min, max) {
  if (!Number.isFinite(n)) return null;
  return Math.max(min, Math.min(max, Math.trunc(n)));
}

// --- Extraction champs (version "validator v2") ---
const symbol = root.symbol ?? null;
const sig_hash = root.sig_hash ?? null;

// Champs core
let validated = payload?.validated;
validated = (validated === true || validated === false) ? validated : null;

let decision = toStringOrNull(payload?.decision);               // "APPROVE" | "WATCH" | "REJECT" (si tu l'as)
let quality_score = clampInt(toIntOrNull(payload?.quality_score), 1, 10);
let reasoning = toStringOrNull(payload?.reasoning);
let chart_pattern = toStringOrNull(payload?.chart_pattern);
let stop_loss_suggestion = toNumberOrNull(payload?.stop_loss_suggestion);

// Champs de contexte/diagnostic
let bias_sma200 = toStringOrNull(payload?.bias_sma200);         // "BULLISH" | "BEARISH" | "NEUTRAL"
let regime_d1 = toStringOrNull(payload?.regime_d1);             // "BULLISH" | "BEARISH" | "NEUTRAL"
let h1_d1_alignment = toStringOrNull(payload?.h1_d1_alignment); // "WITH_BIAS" | "AGAINST_BIAS" | "MIXED"
let stop_loss_basis = toStringOrNull(payload?.stop_loss_basis); // "SWING_H1" | "BAR_ANCHOR" | "NONE"
let missing_fields = toArrayOrEmpty(payload?.missing_fields);
let anomalies = toArrayOrEmpty(payload?.anomalies);

// --- Normalisations / garde-fous ---
// 1) chart_pattern jamais vide
if (!chart_pattern || chart_pattern.trim() === "") chart_pattern = "None";

// 2) stop_loss_basis jamais null
if (isNil(stop_loss_basis) || stop_loss_basis.trim?.() === "") {
  stop_loss_basis = isNil(stop_loss_suggestion) ? "NONE" : "SWING_H1";
}

// 3) Si stop_loss_suggestion null => basis NONE
if (isNil(stop_loss_suggestion)) stop_loss_basis = "NONE";

// 4) Gestion bars manquantes => WATCH si WITH_BIAS
const hasBarsMissing = missing_fields.includes("BARS_H1") || missing_fields.includes("bars") || missing_fields.includes("RECENT_CANDLES");
if (hasBarsMissing && h1_d1_alignment === "WITH_BIAS") {
  decision = "WATCH";
  validated = false;
  // Ajustement de score si incohérent
  if (quality_score !== null && quality_score < 4) quality_score = 5;
}

// 5) Cohérence validated <-> decision (si decision existe)
if (decision) {
  if (decision === "APPROVE") validated = true;
  if (decision === "REJECT" || decision === "WATCH") validated = false;
  // Stop obligatoire si APPROVE : si absent => rétrograder WATCH
  if (decision === "APPROVE" && isNil(stop_loss_suggestion)) {
    decision = "WATCH";
    validated = false;
    stop_loss_basis = "NONE";
    if (quality_score !== null && quality_score > 6) quality_score = 6;
    if (Array.isArray(missing_fields) && !missing_fields.includes("BARS_H1")) missing_fields.push("BARS_H1");
  }
}

// 6) Si reasoning absent => mettre un placeholder traçable
if (!reasoning || reasoning.trim() === "") {
  reasoning = "(no reasoning returned by model)";
}

// --- output_ref ---
// Option A (stable/déterministe) : pas de timestamp => cache facile
const output_ref = `AG2AI|${symbol ?? "NA"}|${sig_hash ?? "NA"}`;
// Option B (unique) : si tu veux conserver l'historique strictement, décommente:
// const ts = new Date().toISOString();
// const output_ref = `AG2AI|${symbol ?? "NA"}|${sig_hash ?? "NA"}|${ts}`;

const ts = new Date().toISOString();

return {
  // Champs normalisés “v2”
  ai_validated: validated,
  ai_decision: decision,
  ai_quality_score: quality_score,
  ai_reasoning: reasoning,
  ai_chart_pattern: chart_pattern,
  ai_stop_loss_suggestion: stop_loss_suggestion,
  ai_stop_loss_basis: stop_loss_basis,

  ai_bias_sma200: bias_sma200,
  ai_regime_d1: regime_d1,
  ai_h1_d1_alignment: h1_d1_alignment,
  ai_missing_fields: missing_fields,
  ai_anomalies: anomalies,

  // brut (utile debug / audit)
  ai_raw: payload ?? null,

  // ref cache / audit
  output_ref,
  output_ref_ts: ts,
};

// AG2.41D — Finalize: output_ref + alignment fallback + pass_to_pm gating

const j = $json ?? {};
const symbol = j.symbol ?? "NA";
const sig = j.sig_hash ?? "NA";

// stable key
const output_ref = `AG2AI|${symbol}|${sig}`;

// helpers
const arr = (v) => Array.isArray(v) ? v : [];
const has = (a, x) => arr(a).includes(x);

// get AI fields
let decision = j.ai_decision ?? j.ai_raw?.decision ?? null;
let validated = (j.ai_validated ?? j.ai_raw?.validated);
let qs = j.ai_quality_score ?? j.ai_raw?.quality_score ?? null;

const bias = j.ai_bias_sma200 ?? j.ai_raw?.bias_sma200 ?? null;
const h1Action =
  j.SIGNAL_TACTICAL_H1?.action ??
  j.technical_analysis?.signal?.action ??
  null;

// alignment fallback
let alignment = j.ai_h1_d1_alignment ?? j.ai_raw?.h1_d1_alignment ?? null;
if ((!alignment || alignment === "UNKNOWN") && bias && h1Action && (h1Action === "BUY" || h1Action === "SELL")) {
  if ((h1Action === "BUY" && bias === "BULLISH") || (h1Action === "SELL" && bias === "BEARISH")) alignment = "WITH_BIAS";
  else alignment = "AGAINST_BIAS";
}

// bars missing rule (garde-fou)
const missing = arr(j.ai_missing_fields ?? j.ai_raw?.missing_fields);
const barsMissing = has(missing, "BARS_H1");

// Si bars manquantes, on n’autorise jamais APPROVE
if (barsMissing) {
  validated = false;
  if (alignment === "WITH_BIAS") {
    decision = "WATCH";
    if (typeof qs !== "number" || qs < 4) qs = 5;
  } else {
    decision = "REJECT";
    if (typeof qs !== "number" || qs > 3) qs = 3;
  }
}

// cohérence decision/validated
if (decision === "APPROVE") validated = true;
if (decision === "WATCH" || decision === "REJECT") validated = false;

// pass_to_pm FINAL (écrase l’amont)
const pass_to_pm =
  (decision === "APPROVE") ||
  (decision === "WATCH" && alignment === "WITH_BIAS" && typeof qs === "number" && qs >= 5);

// JSON strings pour Sheets
const ai_missing_fields_json = JSON.stringify(missing);
const ai_anomalies_json = JSON.stringify(arr(j.ai_anomalies ?? j.ai_raw?.anomalies));

return {
  ...j,
  output_ref,

  ai_decision: decision,
  ai_validated: validated,
  ai_quality_score: qs,
  ai_h1_d1_alignment: alignment,

  pass_to_pm,

  ai_missing_fields_json,
  ai_anomalies_json,
};

// 3F — Build AG2 Input (intraday + daily, robuste)
// Mode: Run once for all items
// Sortie: objet de config + symbols[] + 2 blocs {intraday} et {daily}

const first = $input.first()?.json ?? {};
const all = $input.all().map(i => i.json ?? {});

function uniq(arr) {
  return [...new Set(arr)];
}
function cleanSym(s) {
  return String(s ?? "").trim();
}
function toInt(v, dflt) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.floor(n) : dflt;
}

// 1) Priorité: symbols fournis explicitement (via une variable 'symbols' dans le premier item)
let symbols = Array.isArray(first.symbols) ? first.symbols : [];

// 2) Sinon: marketDataPack.items[].symbol (structure issue de 3E - legacy)
if (!symbols.length && first.marketDataPack && Array.isArray(first.marketDataPack.items)) {
  symbols = first.marketDataPack.items.map(x => x?.symbol);
}

// 3) Sinon: symbolDirectory[].symbol (aussi produit par 3E - legacy)
if (!symbols.length && Array.isArray(first.symbolDirectory)) {
  symbols = first.symbolDirectory.map(x => x?.symbol);
}

// 4) Sinon: cas où chaque item entrant est déjà une ligne avec .Symbol (Votre nouveau format)
// On map sur 'Symbol' (votre clé) ou 'symbol' (standard n8n parfois)
if (!symbols.length) {
  symbols = all.map(x => x.Symbol || x.symbol);
}

// Nettoyage et déduplication
symbols = uniq(symbols.map(cleanSym).filter(s => s !== ""));

// ----- INTRADAY (par défaut inchangé) -----
// Récupère les configs depuis le premier item ou utilise des défauts
const intraday_interval = String(first.interval ?? "1h");
const intraday_lookback_days = toInt(first.lookback_days ?? first.lookbackDays, 60);
const intraday_max_bars = toInt(first.max_bars ?? first.maxBars, 200);

// ----- DAILY (nouveau bloc) -----
const daily_interval = String(first.daily_interval ?? first.dailyInterval ?? "1d");
const daily_lookback_days = toInt(first.daily_lookback_days ?? first.dailyLookbackDays, 400);
const daily_max_bars = toInt(first.daily_max_bars ?? first.dailyMaxBars, 400);

const out = {
  run_id: first.run_id ?? first.runId ?? "",
