// Indicateurs à exporter (canon + H1 + D1)
// IMPORTANT: correspond aux champs produits par ton agrégateur (sma20, h1_sma20, d1_sma20, etc.)
const IND_MAP = [
  ["SMA20", "sma20"],
  ["SMA50", "sma50"],
