// AG2.01B - Batch Rotation (Round Robin)
// Placez ce code dans un noeud "Code" entre AG2.01 et AG2.02

// --- CONFIGURATION ---
const BATCH_SIZE = 25; // Nombre de références à traiter par exécution

// 1. Récupérer la mémoire du workflow
const staticData = $getWorkflowStaticData('global');

// 2. Récupérer l'objet d'entrée (venant de AG2.01)
// On s'attend à un objet contenant un tableau "symbols"
const inputData = $input.first().json;
const fullList = inputData.symbols || [];

// Sécurité : si la liste est vide, on laisse passer tel quel ou on arrête
if (!Array.isArray(fullList) || fullList.length === 0) {
  return [{ json: inputData }];
}

// 3. Récupérer l'index actuel (ou 0 si c'est le premier lancement)
let currentIndex = staticData.lastIndex;
if (typeof currentIndex !== 'number') {
  currentIndex = 0;
}

// 4. Créer le lot (Batch)
// On découpe la liste complète pour ne garder que le segment actuel
const batchSymbols = fullList.slice(currentIndex, currentIndex + BATCH_SIZE);

// 5. Calculer le prochain index pour la future exécution
let nextIndex = currentIndex + BATCH_SIZE;

// Si on a atteint ou dépassé la fin de la liste, on remet le compteur à 0 pour la prochaine fois
if (nextIndex >= fullList.length) {
  nextIndex = 0;
}

// 6. Sauvegarder la position en mémoire
staticData.lastIndex = nextIndex;

// --- DEBUG (visible dans la console du noeud) ---
console.log(`--- EXECUTION BATCH ---`);
console.log(`Total symboles disponibles : ${fullList.length}`);
console.log(`Index de démarrage : ${currentIndex}`);
console.log(`Symboles retenus pour ce run : ${batchSymbols.length}`);
console.log(`Prochain démarrage prévu à : ${nextIndex}`);

// 7. Reconstruire la sortie
// On clone les données d'entrée pour ne pas perdre les configs (run_id, versions, etc.)
// Mais on remplace la liste complète par notre lot réduit.
const outputData = {
  ...inputData,
  symbols: batchSymbols, // On écrase avec la liste courte
  batch_info: {          // On ajoute des infos utiles pour le debug
    start_index: currentIndex,
    batch_size: batchSymbols.length,
    total_pool: fullList.length
  }
};

// On renvoie l'objet modifié vers AG2.02
return [{ json: outputData }];

// AG2.41PRE — Build AI Payload (D1 + H1 signal + candles H1 sample) — SAFE JSON (no NaN)
// + RR_Theoretical injection (TP=Next Resistance, SL=2*ATR or under last trough)

function roundSmart(n) {
  if (typeof n !== "number" || !Number.isFinite(n)) return null;
  if (Math.abs(n) < 0.1 && n !== 0) return Number(n.toFixed(4));
  return Number(n.toFixed(2));
}

function cleanNumbers(obj) {
  if (!obj || typeof obj !== "object") return {};
  const out = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k] = (typeof v === "number") ? roundSmart(v) : v;
  }
  return out;
}

function pickCandles(j) {
  const candidates = [
    j.h1_candles_sample,          // <-- AG2.20
    j.H1_CANDLES_SAMPLE,
    j.intraday_candles_sample,
    j.intraday_bars_sample,
    j.RECENT_CANDLES,
    j.bars_h1,
    j.candles_1h,
    j.bars_1h,
  ];
  for (const c of candidates) if (Array.isArray(c) && c.length) return c;
  return [];
}

function toNumOrNull(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function normalizeCandles(raw) {
  return raw.map(b => {
    const t = b?.t ?? b?.timestamp ?? null;
    const o = roundSmart(toNumOrNull(b?.o ?? b?.open));
    const h = roundSmart(toNumOrNull(b?.h ?? b?.high));
    const l = roundSmart(toNumOrNull(b?.l ?? b?.low));
    const c = roundSmart(toNumOrNull(b?.c ?? b?.close));
    const vRaw = b?.v ?? b?.volume ?? null;
    const v = (vRaw === null || vRaw === undefined) ? null : (Number.isFinite(Number(vRaw)) ? Number(vRaw) : null);

    return { t, o, h, l, c, v };
  }).filter(b => b.t !== null && b.c !== null);
}

function pickFirstNumber(...vals) {
  for (const v of vals) {
    const n = toNumOrNull(v);
    if (n !== null) return n;
  }
  return null;
}

function pickFromObjects(keys, ...objs) {
  for (const o of objs) {
    if (!o || typeof o !== "object") continue;
    for (const k of keys) {
      const n = toNumOrNull(o?.[k]);
      if (n !== null) return n;
    }
  }
  return null;
}

// Compute RR for LONG setups (TP=resistance above entry, SL=2*ATR or trough)
function computeRRTheoretical({ entry, tpPrice, atr, trough }) {
  if (!Number.isFinite(entry) || !Number.isFinite(tpPrice)) {
    return { rr: null, reason: "MISSING_ENTRY_OR_TP" };
  }

  const tpDistance = tpPrice - entry;
  if (!(tpDistance > 0)) {
    return { rr: null, reason: "TP_NOT_ABOVE_ENTRY", tpDistance: roundSmart(tpDistance) };
  }

  const atrNum = Number.isFinite(atr) ? atr : null;
  const slDistanceAtr = (atrNum !== null) ? 2 * atrNum : null;

  // "Sous le dernier creux" (buffer optionnel)
  let slDistanceTrough = null;
  let slPriceTrough = null;
  if (Number.isFinite(trough) && trough < entry) {
    const buffer = (atrNum !== null) ? 0.1 * atrNum : 0; // ajustable
    slPriceTrough = trough - buffer;
    slDistanceTrough = entry - slPriceTrough;
  }

  let slDistance = null;
  let slMethod = null;

  if (slDistanceTrough !== null && slDistanceTrough > 0) {
    slDistance = slDistanceTrough;
    slMethod = "TROUGH";
  } else if (slDistanceAtr !== null && slDistanceAtr > 0) {
    slDistance = slDistanceAtr;
    slMethod = "ATR_2X";
  } else {
    return { rr: null, reason: "MISSING_SL" };
  }

  const rrRaw = tpDistance / slDistance;
  const rr = Number.isFinite(rrRaw) ? Number(rrRaw.toFixed(2)) : null;

  return {
    rr,
    reason: "OK",
    slMethod,
    entry: roundSmart(entry),
    tpPrice: roundSmart(tpPrice),
    tpDistance: roundSmart(tpDistance),
    slDistance: roundSmart(slDistance),
    slPrice: (slMethod === "TROUGH" && slPriceTrough !== null) ? roundSmart(slPriceTrough) : null,
    atr: (atrNum !== null) ? roundSmart(atrNum) : null,
    trough: Number.isFinite(trough) ? roundSmart(trough) : null,
  };
}

return $input.all().map(item => {
  const j = item.json ?? {};

  const h1 = j.technical_analysis ?? {};
  const d1 = j.technical_analysis_1d ?? {};

  const h1Ind = cleanNumbers(h1.indicators);
  const d1Ind = cleanNumbers(d1.indicators);

  const px = pickFirstNumber(d1Ind.last_close, h1Ind.last_close, j.last_close, j.d1_last_close, j.h1_last_close);
  const sma200 = pickFirstNumber(d1Ind.sma200, d1Ind.SMA_200, j.SMA_200);

  let trendStatus = "NEUTRAL";
  let trendReason = "Données insuffisantes";
  if (typeof px === "number" && typeof sma200 === "number" && Number.isFinite(px) && Number.isFinite(sma200) && sma200 > 0) {
    if (px > sma200) {
      trendStatus = "BULLISH (Haussier)";
      trendReason = `Prix (${roundSmart(px)}) > SMA200 (${roundSmart(sma200)}).`;
    } else {
      trendStatus = "BEARISH (Baissier)";
      trendReason = `Prix (${roundSmart(px)}) < SMA200 (${roundSmart(sma200)}).`;
    }
  }

  const rawCandles = pickCandles(j);
  const recentCandles = normalizeCandles(rawCandles).slice(-60);

  const h1Action = h1.signal?.action ?? "NONE";

  // --- RR inputs ---
  // TP = prochaine résistance (priorité D1, fallback H1, fallback champs "globaux")
  const tpPrice = pickFromObjects(
    [
      "next_resistance",
      "Next_Resistance",
      "resistance_level",
      "resistance_level_50",
      "resistance",
      "R1",
    ],
    d1Ind, h1Ind, j
  );

  // ATR = D1 prioritaire
  const atr = pickFromObjects(
    ["atr_value", "ATR", "atr", "d1_atr_value"],
    d1Ind, h1Ind, j
  );

  // Dernier creux (AG2.20) : adapte ici si tu as un nom exact
  const trough = pickFromObjects(
    ["last_trough", "last_swing_low", "swing_low", "last_low", "support_level", "support_last"],
    j, d1Ind, h1Ind
  );

  // Compute RR (LONG only). Si tu veux le calculer “quoi qu’il arrive”, enlève la condition BUY.
  const rrObj = (h1Action === "BUY")
    ? computeRRTheoretical({ entry: px, tpPrice, atr, trough })
    : { rr: null, reason: "NOT_A_BUY_SETUP" };

  return {
    json: {
      symbol: j.symbol,
      run_id: j.run_id ?? "",
      sig_hash: j.sig_hash ?? "",

      PRIMARY_CONTEXT_D1: {
        trend_verdict: trendStatus,
        trend_reason: trendReason,
        indicators: d1Ind,
      },

      SIGNAL_TACTICAL_H1: {
        action: h1Action,
        score: h1.signal?.score ?? 0,
        confidence: roundSmart(Number(h1.signal?.confidence ?? 0)) ?? 0,
        rationale: h1.signal?.rationale ?? [],
        indicators: h1Ind,
      },

      // --- NEW: RR Theoretical injected for AG2.41 AI ---
      RR_Theoretical: rrObj.rr,
      // audit RR (optionnel mais recommandé)
      RR_Theoretical_Reason: rrObj.reason,
      RR_Theoretical_Method: rrObj.slMethod ?? null,
      RR_Theoretical_Entry: rrObj.entry ?? roundSmart(px),
      RR_Theoretical_TP: rrObj.tpPrice ?? (tpPrice !== null ? roundSmart(tpPrice) : null),
      RR_Theoretical_TPDistance: rrObj.tpDistance ?? null,
      RR_Theoretical_SLDistance: rrObj.slDistance ?? null,
      RR_Theoretical_SLPrice: rrObj.slPrice ?? null,
      RR_Theoretical_ATR: rrObj.atr ?? null,
      RR_Theoretical_Trough: rrObj.trough ?? null,
      // -----------------------------------------------

      RECENT_CANDLES: recentCandles,

      // audit utile
      _candles_h1_count: recentCandles.length,
    }
  };
});

// AG2.PRE — Build Cache Index (Bulk Read Optimization)
// Input: Toute la feuille 'ag2_ai_cache' (via un noeud Google Sheets 'Read All')
// Output: Un objet dictionnaire { "SYMBOL": {row_data} }

const allRows = $input.all();
const cacheIndex = {};

for (const item of allRows) {
  const row = item.json;
  // On utilise le symbole comme clé (en majuscule pour être sûr)
  if (row.symbol) {
    const key = String(row.symbol).trim().toUpperCase();
    cacheIndex[key] = row;
  }
}

// On renvoie l'index dans un item unique pour qu'il soit accessible globalement
return [{
  json: {
    cacheIndex: cacheIndex,
    loadedAt: new Date().toISOString()
  }
}];

// AG2.42 — Smart Dedup & AI Trigger (Consolidated)
// Merges Signature + Cache Lookup + TTL Decision
// Objective: Efficiently determine if we need to call the expensive AI Agent.

// --- CONFIGURATION ---
// The name of the node where you built the cache index (Step 1 of this workflow)
const CACHE_NODE_NAME = "AG2.PRE — Build Cache Index"; 

// TTL Settings (Minutes)
const TTL_BUY_MIN = 240;   // 4h: Standard for BUY signals (don't spam)
const TTL_SELL_MIN = 60;   // 1h: Faster for SELL signals (safety first)

// --- HELPERS ---
function bucket(v, step) {
  if (typeof v !== 'number' || !Number.isFinite(v)) return null;
  return Math.round(v / step) * step;
}

function sign(v, eps = 1e-9) {
  if (typeof v !== 'number' || !Number.isFinite(v)) return null;
  if (v > eps) return 1;
  if (v < -eps) return -1;
  return 0;
}

// FNV-1a Hash (Lightweight, no crypto library needed)
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h * 0x01000193) >>> 0;
  }
  return ('00000000' + h.toString(16)).slice(-8);
}

// --- 1. LOAD CACHE INDEX (Once) ---
let cacheIndex = {};
try {
    const indexData = $items(CACHE_NODE_NAME);
    if (indexData && indexData[0]) {
        cacheIndex = indexData[0].json.cacheIndex || {};
    }
} catch (e) {
    // If cache node didn't run or failed, we proceed (safely assuming no cache)
}

const now = new Date();
const results = [];

// --- 2. PROCESS ITEMS ---
for (const item of $input.all()) {
    const j = item.json;
    const h1 = j.technical_analysis;
    const d1 = j.technical_analysis_1d;
    const symbol = (j.symbol || "").trim().toUpperCase();

    // A. CALCULATE SIGNATURE (Discrete Features)
    // We bucket values (RSI by 2, etc) so small noise doesn't trigger a change.
    const sigObj = {
        symbol: symbol,
        reason: j.reason ?? null,
        h1: {
            action: h1?.signal?.action ?? null,
            score: h1?.signal?.score ?? null,
            rsi: bucket(h1?.indicators?.rsi14, 2),
            macd: sign(h1?.indicators?.macd_hist),
            sma20_vs_sma50: (typeof h1?.indicators?.sma20 === 'number' && typeof h1?.indicators?.sma50 === 'number')
                ? (h1.indicators.sma20 > h1.indicators.sma50 ? 1 : 0) : null,
            close_vs_sma50: (typeof h1?.indicators?.last_close === 'number' && typeof h1?.indicators?.sma50 === 'number')
                ? (h1.indicators.last_close > h1.indicators.sma50 ? 1 : 0) : null,
        },
        d1: {
            trend_close_vs_sma200: (typeof d1?.indicators?.last_close === 'number' && typeof d1?.indicators?.sma200 === 'number')
                ? (d1.indicators.last_close > d1.indicators.sma200 ? 1 : 0) : null,
            sma50_vs_sma200: (typeof d1?.indicators?.sma50 === 'number' && typeof d1?.indicators?.sma200 === 'number')
                ? (d1.indicators.sma50 > d1.indicators.sma200 ? 1 : 0) : null,
            rsi: bucket(d1?.indicators?.rsi14, 2),
            macd: sign(d1?.indicators?.macd_hist),
        },
    };

    const sig_json = JSON.stringify(sigObj);
    const sig_hash = fnv1a(sig_json);

    // B. LOOKUP CACHE
    const cachedRow = cacheIndex[symbol] || null;
    const lastHash = cachedRow?.sig_hash ?? null;
    const lastAtRaw = cachedRow?.last_ai_at ?? null;
    const lastAt = lastAtRaw ? new Date(lastAtRaw) : null;

    // C. DECIDE EXECUTION
    const pass_to_pm = (j.pass_to_ai === true);
    // Safety: SELL signals or "Safety" reasons always get shorter TTL (or immediate)
    const isSell = (j.reason === "SELL_SIGNAL_SAFETY") || (h1?.signal?.action === "SELL");
    const ttlMin = isSell ? TTL_SELL_MIN : TTL_BUY_MIN;

    let call_ai = true;
    let dedup_reason = "NO_CACHE";

    if (!pass_to_pm) {
        // If technical filter said NO, we stop here.
        call_ai = false;
        dedup_reason = "FILTERED_OUT_BY_STRATEGY";
    } else if (lastHash && lastHash === sig_hash) {
        // Signature matches cache -> Check TTL
        if (lastAt && Number.isFinite(lastAt.getTime())) {
            const ageMin = (now - lastAt) / 60000;
            if (ageMin < ttlMin) {
                call_ai = false;
                dedup_reason = `UNCHANGED_WITHIN_TTL (${Math.round(ageMin)}m < ${ttlMin}m)`;
            } else {
                call_ai = true;
                dedup_reason = "UNCHANGED_BUT_TTL_EXPIRED";
            }
        } else {
            // Cache exists but no timestamp -> Safety run
            call_ai = true; 
            dedup_reason = "UNCHANGED_NO_TIMESTAMP"; 
        }
    } else if (lastHash) {
        // Signature is different -> Something changed -> Run
        call_ai = true;
        dedup_reason = "SIGNATURE_CHANGED";
    }

    // D. OUTPUT
    results.push({
        json: {
            ...j,
            // Signature info
            sig_hash,
            sig_json,
            signatureAt: now.toISOString(),

            // Decision info
            call_ai,
            dedup_reason,
            ttl_minutes: ttlMin,

            // Carry over useful flags
            pass_to_pm,
            is_sell_mode: isSell,

            // Optional: attach cache row for debugging if needed
            // cache_row: cachedRow 
        }
    });
}

return results;
